```go
const managerCompactionThresholdPercent = 90.0

type ManagerUsageInput struct {
    UsagePercent *float64 `json:"usagePercent,omitempty"`
    Tokens       *int     `json:"tokens,omitempty"`
    Window       *int     `json:"window,omitempty"`
